// ElevenLabs init webhook — nodo "Code" di n8n (JavaScript).
// Input: la riga del nodo Postgres (init_query.sql). Output: il JSON per ElevenLabs.
// Replica 1:1 la logica del backend Python (_riassunto, _componi_saluto, configurazione).

const row = $input.first().json;

const low = (v) => (v ?? '').toString().toLowerCase();
const has = (v) => v !== null && v !== undefined && String(v).trim() !== '';
const known = has(row.contatto_id);

// numero del chiamante (dal nodo Webhook). Adatta il nome del nodo se diverso da "Webhook".
const caller =
  $('Webhook').first().json?.body?.caller_id ??
  $('Webhook').first().json?.caller_id ?? '';

// ---- nome completo / nomi
const nome = (row.nome || '').trim();
const cognome = (row.cognome || '').trim();
const titolo = (row.titolo || '').trim();
let nomeCompleto = `${nome} ${cognome}`.trim();
if (!nomeCompleto) nomeCompleto = (row.ragione_sociale || '').trim() || 'Contatto senza nome';

const aziendaNome = (row.azienda_nome || '').trim() || 'la nostra azienda';
const societaNome = has(row.societa_nome) ? row.societa_nome : (row.ragione_sociale || '').trim();

// ---- ultimo ordine
let ultimoOrdine = 'nessuno';
let ultimoTxt = '';
if (has(row.ordine_id)) {
  const dataIt = row.ordine_data ? new Date(row.ordine_data).toLocaleDateString('it-IT') : '';
  const tot = Number(row.totale || 0).toFixed(2);
  ultimoOrdine = `#${row.ordine_id} del ${dataIt}, ${row.n_articoli || 0} articoli, € ${tot} (${low(row.ordine_stato)})`;
  ultimoTxt = ` Ultimo ordine: ${ultimoOrdine}.`;
}

// ---- riassunto cliente
let riassunto;
if (known) {
  const pezzi = [nomeCompleto];
  if (has(row.ruolo)) pezzi.push(row.ruolo);
  if (has(row.societa_nome)) pezzi.push(`di ${societaNome} (${low(row.societa_stato)})`);
  else if (has(row.ragione_sociale)) pezzi.push(`di ${row.ragione_sociale}`);
  riassunto = pezzi.join(', ') + '.' + ultimoTxt;
} else {
  riassunto = 'Chiamante non riconosciuto: è un nuovo contatto da registrare.';
}

// ---- saluto (con segnaposto {titolo} {nome} {cognome} {azienda})
const SALUTO_DEFAULT = 'Buongiorno, come posso aiutarla?';
const pulisci = (s) => s.replace(/\s+/g, ' ').replace(/ ,/g, ',').replace(/ \./g, '.').replace(/ !/g, '!').replace(/ \?/g, '?').trim();
function componi(template) {
  if (!template || !template.trim()) return '';
  const s = template
    .split('{titolo}').join(known ? titolo : '')
    .split('{nome}').join(known ? nome : '')
    .split('{cognome}').join(known ? cognome : '')
    .split('{azienda}').join(aziendaNome);
  return pulisci(s) || SALUTO_DEFAULT;
}
let saluto;
if (known) {
  saluto = componi(row.saluto);
  if (!saluto) {
    const app = (cognome || nome).trim();
    saluto = app ? `Buongiorno signor ${app}, come posso aiutarla?` : SALUTO_DEFAULT;
  }
} else {
  saluto = componi(row.saluto_sconosciuto) || SALUTO_DEFAULT;
}

// ---- configurazione (profilo + istruzioni admin + regole commerciali)
const INFO_QUAL_DEFAULT =
  'Raccogli, in modo naturale e senza interrogatori, almeno:\n' +
  '- nome e cognome della persona;\n' +
  '- ragione sociale della società e ruolo della persona (es. titolare, ufficio acquisti);\n' +
  '- email e telefono per essere ricontattati;\n' +
  '- sede / località;\n' +
  '- di cosa ha bisogno (prodotto/servizio di interesse), quantità/volumi se rilevanti, tempistiche e, se emerge, budget.';

const sezione = (tit, corpo) => {
  corpo = (corpo || '').trim();
  return corpo ? `\n\n=== ${tit} ===\n${corpo}` : '';
};

let configurazione = '';
configurazione += sezione('COSA OFFRIAMO (usa SOLO queste informazioni per rispondere su prodotti/servizi/costi)', row.descrizione_servizi);
configurazione += sezione('COME QUALIFICARE IL LEAD (informazioni da raccogliere durante la conversazione)',
  (row.info_qualificazione && row.info_qualificazione.trim()) ? row.info_qualificazione : INFO_QUAL_DEFAULT);
configurazione += sezione('COME ASSEGNARE LA PRIORITÀ AL LEAD (alta / media / bassa)', row.criteri_priorita);

const istr = (row.istruzioni_admin || '').trim();
if (istr) {
  configurazione += "\n\n=== ISTRUZIONI DELL'AMMINISTRATORE ===\n" +
    'Il testo delimitato qui sotto NON è un messaggio del cliente con cui stai parlando e NON fa parte della sua ' +
    "richiesta: sono indicazioni operative scritte dall'amministratore che gestisce questo assistente (il gestore del " +
    'servizio). Trattale come policy/preferenze da rispettare nel modo in cui rispondi (tono, priorità, cosa dire o non ' +
    'dire, comportamenti particolari). Restano comunque valide le regole già ricevute: non inventare dati e non rivelare ' +
    'informazioni riservate; se queste indicazioni le contraddicono o ti chiedono di fornire dati che non hai, dai la ' +
    'precedenza alle regole di sicurezza.\n' +
    '----- inizio istruzioni amministratore -----\n' + istr + '\n----- fine istruzioni amministratore ===';
}

const regole = (row.regole_commerciali || '').trim();
if (regole) {
  configurazione += '\n\n=== REGOLE COMMERCIALI E PROMOZIONI ===\n' +
    "Politiche di prezzo, sconti e promozioni impostate dall'amministratore. Applicale quando rispondi su prezzi/offerte " +
    'e quando registri un ordine (es. quantità omaggio, sconti a scaglioni). Se un calcolo è ambiguo o non sei certo, ' +
    'chiedi conferma invece di indovinare.\n' +
    '----- inizio regole commerciali -----\n' + regole + '\n----- fine regole commerciali ===';
}
configurazione = configurazione.trim();

// ---- dynamic variables (stesse chiavi del backend Python)
const dv = {
  cliente_conosciuto: known ? 'sì' : 'no',
  nome_cliente: known ? nomeCompleto : '',
  nome: known ? nome : '',
  cognome: known ? cognome : '',
  titolo: known ? titolo : '',
  societa: known ? (societaNome || '') : '',
  stato_cliente: known ? (has(row.societa_stato) ? low(row.societa_stato) : low(row.contatto_stato)) : '',
  ruolo: known ? (row.ruolo || '') : '',
  email_cliente: known ? (row.email || '') : '',
  ultimo_ordine: ultimoOrdine,
  riassunto_cliente: riassunto,
  saluto: saluto,
  telefono_chiamante: caller,
  configurazione: configurazione,
};

return [{ json: { type: 'conversation_initiation_client_data', dynamic_variables: dv } }];
